namespace optiling {

// UB budget for cube: each tile uses A(tileM*tileK), B(tileK*tileN), C(tileM*tileN) floats
static constexpr uint32_t UB_BUDGET_BYTES = 448 * 1024; // Cube L0A+L0B+L0C approx
static constexpr uint32_t ALIGN = 64; // cube alignment

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    TallSkinnyMatrixMultiplicationCustomTilingData tiling;
    const auto& a_shape = context->GetInputShape(0)->GetOriginShape();
    const auto& b_shape = context->GetInputShape(1)->GetOriginShape();
    uint32_t m = a_shape.GetDim(0);
    uint32_t k = a_shape.GetDim(1);
    uint32_t n = b_shape.GetDim(1);

    // Cube prefers multiples of 16
    constexpr uint32_t CUBE_ALIGN = 16;
    m = AlignDown(m, CUBE_ALIGN) ? AlignDown(m, CUBE_ALIGN) : m;
    k = AlignDown(k, CUBE_ALIGN) ? AlignDown(k, CUBE_ALIGN) : k;
    n = AlignDown(n, CUBE_ALIGN) ? AlignDown(n, CUBE_ALIGN) : n;

    // Heuristic tile sizes
    uint32_t tileM = 128;  // typical cube tile
    uint32_t tileK = 64;
    uint32_t tileN = 128;

    // Ensure tile sizes fit UB budget (4 bytes per float)
    uint32_t bytesPerTile = (tileM * tileK + tileK * tileN + tileM * tileN) * 4;
    while (bytesPerTile > UB_BUDGET_BYTES && tileM > 16) {
        tileM >>= 1;
        tileN >>= 1;
        bytesPerTile = (tileM * tileK + tileK * tileN + tileM * tileN) * 4;
    }

    if (m < tileM) tileM = m;
    if (k < tileK) tileK = k;
    if (n < tileN) tileN = n;

    // Block dim: number of tiles in M dimension (since N small, we just use parallel in M)
    uint32_t numTilesM = CeilDiv(m, tileM);
    uint32_t blockDim = numTilesM;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(m * n);
    tiling.set_m(m);
    tiling.set_k(k);
    tiling.set_n(n);
    tiling.set_tileM(tileM);
    tiling.set_tileK(tileK);
    tiling.set_tileN(tileN);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

